var body = $input.first().json.body || $input.first().json;

if (!body.tenantId || !body.email) {
  throw new Error('tenantId and email are required');
}

function esc(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }

var validSources = ['manual','lead','client','contact_form','import_csv','api'];
var source = validSources.indexOf(body.source) >= 0 ? body.source : 'manual';

var tagsVal = 'NULL';
if (body.tags && Array.isArray(body.tags) && body.tags.length > 0) {
  tagsVal = 'ARRAY[' + body.tags.map(function(t) { return esc(t); }).join(',') + ']::text[]';
}

var query = "INSERT INTO subscribers (tenant_id, email, telephone, nom, prenom, entreprise, source, tags) VALUES ("
  + esc(body.tenantId) + "::uuid, "
  + esc(body.email) + ", "
  + esc(body.telephone) + ", "
  + esc(body.nom) + ", "
  + esc(body.prenom) + ", "
  + esc(body.entreprise) + ", "
  + esc(source) + ", "
  + tagsVal + ")"
  + ' ON CONFLICT (tenant_id, email) DO UPDATE SET'
  + ' telephone = COALESCE(EXCLUDED.telephone, subscribers.telephone),'
  + ' nom = COALESCE(EXCLUDED.nom, subscribers.nom),'
  + ' prenom = COALESCE(EXCLUDED.prenom, subscribers.prenom),'
  + ' entreprise = COALESCE(EXCLUDED.entreprise, subscribers.entreprise),'
  + ' updated_at = NOW()'
  + ' RETURNING id, tenant_id AS "tenantId", email, telephone, nom, prenom, entreprise, status, source, tags, created_at AS "createdAt", updated_at AS "updatedAt"';

return [{ json: { tenantId: body.tenantId, query: query } }];

var items = $('05. Upsert Query').all();
var subscriber = items[0] ? items[0].json : {};
return [{ json: { subscriber: subscriber } }];
